sys_script_email.script:
var mlt = new x_1880990_chain.MagicLinkToken();
  var base = gs.getProperty('glide.servlet.uri') + 'api/x_1880990_chain/chain_magic_link/';
  var proposalId = current.sys_id.toString();
  var managerId = current.state_manager.toString();

  var urlApprove = base + 'approve?token=' + mlt.generate(proposalId, managerId, 'approve');
  var urlReject = base + 'reject?token=' + mlt.generate(proposalId, managerId, 'reject');

  var btnStyle = 'display: inline-block; padding: 12px 24px; margin: 0 6px; color: white; text-decoration: none; border-radius: 4px; font-weight: bold;';

  template.print(
      '<div style="text-align: center; margin: 32px 0;">' +
      '<a href="' + urlApprove + '" style="' + btnStyle + ' background: #27ae60;">Aprovar</a>' +
      '<a href="' + urlReject + '" style="' + btnStyle + ' background: #c0392b;">Rejeitar</a>' +
      '</div>'
  );
